import React, { useEffect, useState } from 'react';
import { Icon } from '@capital/component';
import { usePlayerStore } from '../../store/playerStore';
import { useSettingsStore } from '../../store/settingsStore';
import { getPicUrl } from '../../api/musicApi';
import { FavoriteButton, ModeButton, PlayControls, ProgressBar, VolumeControl } from './Controls';

export const MiniBar: React.FC<{ onExpand: () => void; onClose: () => void }> = ({
  onExpand,
  onClose,
}) => {
  const song = usePlayerStore((s) => s.currentSong);
  const [cover, setCover] = useState('');

  useEffect(() => {
    if (song?.pic_id) {
      getPicUrl(song.pic_id, song.source).then(setCover).catch(() => undefined);
    } else {
      setCover('');
    }
  }, [song?.pic_id, song?.source]);

  return (
    <div
      style={{
        position: 'fixed',
        right: 16,
        bottom: 16,
        zIndex: 999999,
        width: 320,
        borderRadius: 14,
        background: 'rgba(24,24,27,0.92)',
        color: '#fff',
        boxShadow: '0 8px 24px rgba(0,0,0,0.35)',
        backdropFilter: 'blur(10px)',
        padding: '10px 12px',
        fontFamily: 'inherit',
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
        <div
          style={{
            width: 40,
            height: 40,
            borderRadius: 8,
            overflow: 'hidden',
            flexShrink: 0,
            background: 'linear-gradient(135deg,#667eea,#764ba2)',
          }}
          onClick={onExpand}
        >
          {cover && <img src={cover} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
        </div>
        <div style={{ flex: 1, minWidth: 0, cursor: 'pointer' }} onClick={onExpand}>
          <div
            style={{
              fontSize: 13,
              fontWeight: 600,
              whiteSpace: 'nowrap',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
            }}
          >
            {song ? song.name : '未播放任何歌曲'}
          </div>
          <div
            style={{
              fontSize: 11,
              opacity: 0.6,
              whiteSpace: 'nowrap',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
            }}
          >
            {song?.artist || '打开音乐面板搜索歌曲吧'}
          </div>
        </div>
        <FavoriteButton size={16} color="#fff" />
        <div
          style={{ cursor: 'pointer', opacity: 0.6, display: 'flex' }}
          title="收起"
          onClick={onClose}
        >
          <Icon icon="mdi:chevron-down" width={18} color="#fff" />
        </div>
      </div>

      <div style={{ marginTop: 8 }}>
        <ProgressBar />
      </div>

      <div style={{ marginTop: 6, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <ModeButton size={16} color="#fff" />
        <PlayControls size={18} color="#fff" />
        <VolumeControl color="#fff" />
      </div>
    </div>
  );
};

/** 收起后显示的悬浮小圆点，点击可重新唤出播放器 */
export const CollapsedDot: React.FC<{ onOpen: () => void }> = ({ onOpen }) => {
  const playing = usePlayerStore((s) => s.playing);
  const settings = useSettingsStore((s) => s.settings);
  if (!settings.mediaKeysEnabled) {
    /* no-op just to subscribe */
  }
  return (
    <div
      onClick={onOpen}
      style={{
        position: 'fixed',
        right: 16,
        bottom: 16,
        zIndex: 999999,
        width: 46,
        height: 46,
        borderRadius: '50%',
        background: 'rgba(24,24,27,0.9)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        cursor: 'pointer',
        boxShadow: '0 6px 16px rgba(0,0,0,0.3)',
      }}
      title="打开音乐播放器"
    >
      <Icon icon={playing ? 'mdi:music-note' : 'mdi:music-note-outline'} width={22} color="#fff" />
    </div>
  );
};
