import React, { useEffect, useState } from 'react';
import { Icon } from '@capital/component';
import { showToasts } from '@capital/common';
import { Playlist, Song } from '../../const';
import {
  createPlaylist,
  deletePlaylist,
  getFavorites,
  getPlaylists,
  removeSongFromPlaylist,
  renamePlaylist,
} from '../../utils/storage';
import { usePlayerStore } from '../../store/playerStore';
import { SongRow } from './SongRow';
import { buildPlaylistCardContent } from '../../utils/share';

const FAVORITES_ID = '__favorites__';

export const Playlists: React.FC = () => {
  const [playlists, setPlaylists] = useState<Playlist[]>(getPlaylists());
  const [favorites, setFavorites] = useState<Song[]>(getFavorites());
  const [openId, setOpenId] = useState<string | null>(null);
  const [newName, setNewName] = useState('');
  const playSong = usePlayerStore((s) => s.playSong);

  useEffect(() => {
    const refresh = () => {
      setPlaylists(getPlaylists());
      setFavorites(getFavorites());
    };
    window.addEventListener('musicplayer:playlists-changed', refresh);
    window.addEventListener('musicplayer:favorites-changed', refresh);
    return () => {
      window.removeEventListener('musicplayer:playlists-changed', refresh);
      window.removeEventListener('musicplayer:favorites-changed', refresh);
    };
  }, []);

  const virtualFavPlaylist: Playlist = {
    id: FAVORITES_ID,
    name: '我的收藏',
    createdAt: 0,
    songs: favorites,
  };

  const list = [virtualFavPlaylist, ...playlists];

  const copyShare = async (playlist: Playlist) => {
    try {
      await navigator.clipboard.writeText(buildPlaylistCardContent(playlist));
      showToasts('歌单分享卡片已复制，可粘贴到任意聊天窗口发送', 'success');
    } catch {
      showToasts('复制失败', 'error');
    }
  };

  return (
    <div style={{ height: '100%', overflowY: 'auto', padding: 12 }}>
      <div style={{ display: 'flex', gap: 6, marginBottom: 10 }}>
        <input
          value={newName}
          onChange={(e) => setNewName(e.target.value)}
          placeholder="新建歌单名称"
          style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid rgba(120,120,120,0.3)', background: 'transparent', color: 'inherit' }}
        />
        <div
          onClick={() => {
            if (!newName.trim()) return;
            createPlaylist(newName.trim());
            setNewName('');
          }}
          style={{ display: 'flex', alignItems: 'center', padding: '0 12px', borderRadius: 6, background: '#22c55e', color: '#fff', cursor: 'pointer' }}
        >
          <Icon icon="mdi:plus" width={16} />
        </div>
      </div>

      {list.map((pl) => (
        <div key={pl.id} style={{ marginBottom: 8, border: '1px solid rgba(120,120,120,0.2)', borderRadius: 10, overflow: 'hidden' }}>
          <div
            style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '10px 12px', cursor: 'pointer' }}
            onClick={() => setOpenId(openId === pl.id ? null : pl.id)}
          >
            <Icon icon={pl.id === FAVORITES_ID ? 'mdi:heart' : 'mdi:playlist-music'} width={18} />
            <div style={{ flex: 1, fontWeight: 600, fontSize: 13 }}>{pl.name}</div>
            <span style={{ fontSize: 12, opacity: 0.5 }}>{pl.songs.length}首</span>

            {pl.songs.length > 0 && (
              <Icon
                icon="mdi:play-circle-outline"
                width={18}
                onClick={(e: any) => {
                  e.stopPropagation();
                  playSong(pl.songs[0], pl.songs);
                }}
              />
            )}
            {pl.id !== FAVORITES_ID && (
              <Icon
                icon="mdi:share-variant"
                width={16}
                onClick={(e: any) => {
                  e.stopPropagation();
                  copyShare(pl);
                }}
              />
            )}
            {pl.id !== FAVORITES_ID && (
              <Icon
                icon="mdi:pencil"
                width={16}
                onClick={(e: any) => {
                  e.stopPropagation();
                  const name = window.prompt('重命名歌单', pl.name);
                  if (name) renamePlaylist(pl.id, name);
                }}
              />
            )}
            {pl.id !== FAVORITES_ID && (
              <Icon
                icon="mdi:delete-outline"
                width={16}
                onClick={(e: any) => {
                  e.stopPropagation();
                  if (window.confirm(`删除歌单《${pl.name}》?`)) deletePlaylist(pl.id);
                }}
              />
            )}
          </div>

          {openId === pl.id && (
            <div style={{ padding: '0 10px 10px' }}>
              {pl.songs.length === 0 && <div style={{ opacity: 0.4, fontSize: 12, padding: 8 }}>暂无歌曲</div>}
              {pl.songs.map((song, i) => (
                <div key={`${song.source}-${song.id}`} style={{ display: 'flex', alignItems: 'center' }}>
                  <div style={{ flex: 1 }}>
                    <SongRow song={song} queue={pl.songs} index={i} />
                  </div>
                  {pl.id !== FAVORITES_ID && (
                    <Icon
                      icon="mdi:close"
                      width={14}
                      style={{ cursor: 'pointer', opacity: 0.5, marginLeft: 4 }}
                      onClick={() => removeSongFromPlaylist(pl.id, song.id, song.source)}
                    />
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      ))}
    </div>
  );
};
