import React from 'react';
import { Icon } from '@capital/component';
import { usePlayerStore } from '../../store/playerStore';
import { isFavorite, toggleFavorite } from '../../utils/storage';

const btnStyle: React.CSSProperties = {
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  opacity: 0.85,
};

export const modeIcon: Record<string, string> = {
  order: 'mdi:repeat',
  random: 'mdi:shuffle-variant',
  loop: 'mdi:repeat-once',
};

export const modeLabel: Record<string, string> = {
  order: '顺序播放',
  random: '随机播放',
  loop: '单曲循环',
};

export const PlayControls: React.FC<{ size?: number; color?: string }> = ({
  size = 22,
  color,
}) => {
  const playing = usePlayerStore((s) => s.playing);
  const togglePlay = usePlayerStore((s) => s.togglePlay);
  const next = usePlayerStore((s) => s.next);
  const prev = usePlayerStore((s) => s.prev);

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
      <div style={btnStyle} onClick={prev} title="上一首">
        <Icon icon="mdi:skip-previous" width={size} color={color} />
      </div>
      <div style={{ ...btnStyle }} onClick={togglePlay} title={playing ? '暂停' : '播放'}>
        <Icon icon={playing ? 'mdi:pause-circle' : 'mdi:play-circle'} width={size * 1.7} color={color} />
      </div>
      <div style={btnStyle} onClick={next} title="下一首">
        <Icon icon="mdi:skip-next" width={size} color={color} />
      </div>
    </div>
  );
};

export const ModeButton: React.FC<{ size?: number; color?: string }> = ({ size = 18, color }) => {
  const mode = usePlayerStore((s) => s.mode);
  const cycleMode = usePlayerStore((s) => s.cycleMode);
  return (
    <div style={btnStyle} onClick={cycleMode} title={modeLabel[mode]}>
      <Icon icon={modeIcon[mode]} width={size} color={color} />
    </div>
  );
};

export const FavoriteButton: React.FC<{ size?: number; color?: string }> = ({
  size = 18,
  color,
}) => {
  const song = usePlayerStore((s) => s.currentSong);
  const [fav, setFav] = React.useState(() => (song ? isFavorite(song) : false));

  React.useEffect(() => {
    setFav(song ? isFavorite(song) : false);
  }, [song?.id, song?.source]);

  if (!song) return null;

  return (
    <div
      style={btnStyle}
      title={fav ? '取消收藏' : '收藏'}
      onClick={() => setFav(toggleFavorite(song))}
    >
      <Icon icon={fav ? 'mdi:heart' : 'mdi:heart-outline'} width={size} color={fav ? '#f43f5e' : color} />
    </div>
  );
};

export const VolumeControl: React.FC<{ color?: string }> = ({ color }) => {
  const volume = usePlayerStore((s) => s.volume);
  const muted = usePlayerStore((s) => s.muted);
  const setVolume = usePlayerStore((s) => s.setVolume);
  const toggleMute = usePlayerStore((s) => s.toggleMute);
  const [open, setOpen] = React.useState(false);

  return (
    <div style={{ position: 'relative', display: 'flex', alignItems: 'center' }}>
      <div style={btnStyle} onClick={() => setOpen((o) => !o)} title="音量">
        <Icon
          icon={muted || volume === 0 ? 'mdi:volume-mute' : volume < 0.5 ? 'mdi:volume-medium' : 'mdi:volume-high'}
          width={18}
          color={color}
        />
      </div>
      {open && (
        <div
          style={{
            position: 'absolute',
            bottom: 26,
            left: -6,
            background: 'rgba(30,30,30,0.9)',
            borderRadius: 8,
            padding: '10px 6px',
            display: 'flex',
            justifyContent: 'center',
          }}
        >
          <input
            type="range"
            min={0}
            max={1}
            step={0.01}
            value={muted ? 0 : volume}
            onChange={(e) => setVolume(Number(e.target.value))}
            style={{ writingMode: 'vertical-lr' as any, direction: 'rtl', height: 70 }}
            onClick={() => toggleMute()}
          />
        </div>
      )}
    </div>
  );
};

function formatTime(sec: number): string {
  if (!isFinite(sec) || sec < 0) sec = 0;
  const m = Math.floor(sec / 60);
  const s = Math.floor(sec % 60);
  return `${m}:${String(s).padStart(2, '0')}`;
}

export const ProgressBar: React.FC<{ color?: string; trackColor?: string }> = ({
  color = '#22c55e',
  trackColor = 'rgba(255,255,255,0.25)',
}) => {
  const currentTime = usePlayerStore((s) => s.currentTime);
  const duration = usePlayerStore((s) => s.duration);
  const seek = usePlayerStore((s) => s.seek);
  const percent = duration > 0 ? (currentTime / duration) * 100 : 0;

  const handleClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const ratio = (e.clientX - rect.left) / rect.width;
    seek(Math.max(0, Math.min(1, ratio)) * duration);
  };

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 6, width: '100%' }}>
      <span style={{ fontSize: 11, opacity: 0.7, minWidth: 32 }}>{formatTime(currentTime)}</span>
      <div
        onClick={handleClick}
        style={{
          flex: 1,
          height: 5,
          borderRadius: 3,
          background: trackColor,
          cursor: 'pointer',
          position: 'relative',
        }}
      >
        <div
          style={{
            position: 'absolute',
            left: 0,
            top: 0,
            bottom: 0,
            width: `${percent}%`,
            borderRadius: 3,
            background: color,
          }}
        />
      </div>
      <span style={{ fontSize: 11, opacity: 0.7, minWidth: 32 }}>{formatTime(duration)}</span>
    </div>
  );
};
