import { Playlist, Song, STORAGE_KEYS } from '../const';

function safeParse<T>(str: string | null, fallback: T): T {
  if (!str) return fallback;
  try {
    return JSON.parse(str) as T;
  } catch {
    return fallback;
  }
}

// ---------- 歌单 ----------
export function getPlaylists(): Playlist[] {
  return safeParse<Playlist[]>(localStorage.getItem(STORAGE_KEYS.playlists), []);
}

function savePlaylists(playlists: Playlist[]) {
  localStorage.setItem(STORAGE_KEYS.playlists, JSON.stringify(playlists));
  window.dispatchEvent(new CustomEvent('musicplayer:playlists-changed'));
}

export function createPlaylist(name: string): Playlist {
  const playlists = getPlaylists();
  const playlist: Playlist = {
    id: `pl_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    name,
    createdAt: Date.now(),
    songs: [],
  };
  playlists.push(playlist);
  savePlaylists(playlists);
  return playlist;
}

export function deletePlaylist(id: string) {
  savePlaylists(getPlaylists().filter((p) => p.id !== id));
}

export function renamePlaylist(id: string, name: string) {
  const playlists = getPlaylists();
  const target = playlists.find((p) => p.id === id);
  if (target) {
    target.name = name;
    savePlaylists(playlists);
  }
}

export function addSongToPlaylist(playlistId: string, song: Song) {
  const playlists = getPlaylists();
  const target = playlists.find((p) => p.id === playlistId);
  if (target && !target.songs.some((s) => s.id === song.id && s.source === song.source)) {
    target.songs.push(song);
    savePlaylists(playlists);
  }
}

export function removeSongFromPlaylist(playlistId: string, songId: string, source: string) {
  const playlists = getPlaylists();
  const target = playlists.find((p) => p.id === playlistId);
  if (target) {
    target.songs = target.songs.filter((s) => !(s.id === songId && s.source === source));
    savePlaylists(playlists);
  }
}

// ---------- 收藏 ----------
export function getFavorites(): Song[] {
  return safeParse<Song[]>(localStorage.getItem(STORAGE_KEYS.favorites), []);
}

function saveFavorites(songs: Song[]) {
  localStorage.setItem(STORAGE_KEYS.favorites, JSON.stringify(songs));
  window.dispatchEvent(new CustomEvent('musicplayer:favorites-changed'));
}

export function isFavorite(song: Song): boolean {
  return getFavorites().some((s) => s.id === song.id && s.source === song.source);
}

export function toggleFavorite(song: Song): boolean {
  const favorites = getFavorites();
  const idx = favorites.findIndex((s) => s.id === song.id && s.source === song.source);
  if (idx >= 0) {
    favorites.splice(idx, 1);
    saveFavorites(favorites);
    return false;
  } else {
    favorites.unshift(song);
    saveFavorites(favorites);
    return true;
  }
}

// ---------- 历史 ----------
export function pushHistory(song: Song) {
  const history = safeParse<Song[]>(localStorage.getItem(STORAGE_KEYS.history), []);
  const filtered = history.filter((s) => !(s.id === song.id && s.source === song.source));
  filtered.unshift(song);
  localStorage.setItem(STORAGE_KEYS.history, JSON.stringify(filtered.slice(0, 50)));
}

export function getHistory(): Song[] {
  return safeParse<Song[]>(localStorage.getItem(STORAGE_KEYS.history), []);
}
