import { useSyncExternalStore } from 'react';

type Listener = () => void;
type SetState<T> = (partial: Partial<T> | ((state: T) => Partial<T>)) => void;
type GetState<T> = () => T;

/**
 * 极简 zustand 风格 store 实现，不依赖任何外部包。
 * 之所以不直接使用 `zustand`，是因为它需要宿主 Tailchat 在
 * `mini-star` 运行时中通过 `regDependency('zustand', ...)` 提前注册为
 * 共享模块——不同版本/部署的 Tailchat 是否包含这行代码无法保证，
 * 一旦缺失会导致整个插件加载失败。自实现可以彻底规避这个风险。
 */
export function createStore<T>(
  initializer: (set: SetState<T>, get: GetState<T>) => T
) {
  let state: T;
  const listeners = new Set<Listener>();

  const setState: SetState<T> = (partial) => {
    const patch = typeof partial === 'function' ? (partial as any)(state) : partial;
    state = { ...state, ...patch };
    listeners.forEach((l) => l());
  };

  const getState: GetState<T> = () => state;

  const subscribe = (listener: Listener) => {
    listeners.add(listener);
    return () => listeners.delete(listener);
  };

  state = initializer(setState, getState);

  function useStore<U = T>(selector?: (state: T) => U): U {
    return useSyncExternalStore(
      subscribe,
      () => (selector ? selector(state) : (state as unknown as U))
    );
  }

  useStore.getState = getState;
  useStore.setState = setState;
  useStore.subscribe = subscribe;

  return useStore;
}
